import React from 'react'

export const DashboardContent = (props) => {
  const data = props.data
  return (
    <div>{
      props.pagecontent === "none" ? (
        <div>None</div>
      ) :      
      data.map((item)=>{
      return item.id === props.pagecontent ? (
        <div>{item.content}</div>
      ): null
    })}</div>
  )
}
